-- ============================================================

-- The Real Number System (N-RN)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.RN.A.1', 'Explain how the definition of the meaning of rational exponents follows from extending the properties of integer exponents to those values, allowing for a notation for radicals in terms of rational exponents.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.RN.A.2', 'Rewrite expressions involving radicals and rational exponents using the properties of exponents.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.RN.B.3', 'Explain why the sum or product of two rational numbers is rational; that the sum of a rational number and an irrational number is irrational; and that the product of a nonzero rational number and an irrational number is irrational.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),

-- Quantities (N-Q)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.Q.A.1', 'Use units as a way to understand problems and to guide the solution of multi-step problems; choose and interpret units consistently in formulas; choose and interpret the scale and the origin in graphs and data displays.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.Q.A.2', 'Define appropriate quantities for the purpose of descriptive modeling.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.Q.A.3', 'Choose a level of accuracy appropriate to limitations on measurement when reporting quantities.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),

-- The Complex Number System (N-CN)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.A.1', 'Know there is a complex number i such that i² = −1, and every complex number has the form a + bi with a and b real.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.A.2', 'Use the relation i² = –1 and the commutative, associative, and distributive properties to add, subtract, and multiply complex numbers.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.A.3', 'Find the conjugate of a complex number; use conjugates to find moduli and quotients of complex numbers.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.B.4', 'Represent complex numbers on the complex plane in rectangular and polar form (including real and imaginary numbers), and explain why the rectangular and polar forms of a given complex number represent the same number.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.B.5', 'Represent addition, subtraction, multiplication, and conjugation of complex numbers geometrically on the complex plane; use properties of this representation for computation.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.B.6', 'Calculate the distance between numbers in the complex plane as the modulus of the difference, and the midpoint of a segment as the average of the numbers at its endpoints.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.C.7', 'Solve quadratic equations with real coefficients that have complex solutions.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.C.8', 'Extend polynomial identities to the complex numbers.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.CN.C.9', 'Know the Fundamental Theorem of Algebra; show that it is true for quadratic polynomials.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),

-- Vector & Matrix Quantities (N-VM)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.A.1', 'Recognize vector quantities as having both magnitude and direction. Represent vector quantities by directed line segments, and use appropriate symbols for vectors and their magnitudes.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.A.2', 'Find the components of a vector by subtracting the coordinates of an initial point from the coordinates of a terminal point.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.A.3', 'Solve problems involving velocity and other quantities that can be represented by vectors.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.B.4', 'Add and subtract vectors.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.B.4a', 'Add vectors end-to-end, component-wise, and by the parallelogram rule. Understand that the magnitude of a sum of two vectors is typically not the sum of the magnitudes.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.B.4b', 'Given two vectors in magnitude and direction form, determine the magnitude and direction of their sum.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.B.4c', 'Understand vector subtraction v – w as v + (–w), where –w is the additive inverse of w. Represent vector subtraction graphically by connecting the tips in the appropriate order, and perform vector subtraction component-wise.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.B.5', 'Multiply a vector by a scalar.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.6', 'Use matrices to represent and manipulate data.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.7', 'Multiply matrices by scalars to produce new matrices.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.8', 'Add, subtract, and multiply matrices of appropriate dimensions.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.9', 'Understand that, unlike multiplication of numbers, matrix multiplication for square matrices is not a commutative operation, but still satisfies the associative and distributive properties.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.10', 'Understand that the zero and identity matrices play a role in matrix addition and multiplication similar to the role of 0 and 1 in the real numbers. The determinant of a square matrix is nonzero if and only if the matrix has a multiplicative inverse.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.11', 'Multiply a vector (regarded as a matrix with one column) by a matrix of suitable dimensions to produce another vector. Work with matrices as transformations of vectors.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSN.VM.C.12', 'Work with 2 × 2 matrices as transformations of the plane, and interpret the absolute value of the determinant in terms of area.', 'Number & Quantity', 'Common Core State Standards', true, true, '2010'),

-- ============================================================
-- MATHEMATICS: HIGH SCHOOL — Algebra
-- ============================================================

-- Seeing Structure in Expressions (A-SSE)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.A.1', 'Interpret expressions that represent a quantity in terms of its context.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.A.1a', 'Interpret parts of an expression, such as terms, factors, and coefficients.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.A.1b', 'Interpret complicated expressions by viewing one or more of their parts as a single entity.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.A.2', 'Use the structure of an expression to identify ways to rewrite it.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.B.3', 'Choose and produce an equivalent form of an expression to reveal and explain properties of the quantity represented by the expression.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.B.3a', 'Factor a quadratic expression to reveal the zeros of the function it defines.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.B.3b', 'Complete the square in a quadratic expression to reveal the maximum or minimum value of the function it defines.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.B.3c', 'Use the properties of exponents to transform expressions for exponential functions.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.SSE.B.4', 'Derive the formula for the sum of a finite geometric series (when the common ratio is not 1), and use the formula to solve problems.', 'Algebra', 'Common Core State Standards', true, true, '2010'),

-- Arithmetic with Polynomials & Rational Expressions (A-APR)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.A.1', 'Understand that polynomials form a system analogous to the integers, namely, they are closed under the operations of addition, subtraction, and multiplication; add, subtract, and multiply polynomials.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.B.2', 'Know and apply the Remainder Theorem: For a polynomial p(x) and a number a, the remainder on division by x – a is p(a), so p(a) = 0 if and only if (x – a) is a factor of p(x).', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.B.3', 'Identify zeros of polynomials when suitable factorizations are available, and use the zeros to construct a rough graph of the function defined by the polynomial.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.C.4', 'Prove polynomial identities and use them to describe numerical relationships.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.C.5', 'Know and apply the Binomial Theorem for the expansion of (x + y)^n in powers of x and y for a positive integer n, where x and y are any numbers, with coefficients determined for example by Pascal''s Triangle.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.D.6', 'Rewrite simple rational expressions in different forms; write a(x)/b(x) in the form q(x) + r(x)/b(x), where a(x), b(x), q(x), and r(x) are polynomials with the degree of r(x) less than the degree of b(x), using inspection, long division, or, for the more complicated examples, a computer algebra system.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.APR.D.7', 'Understand that rational expressions form a system analogous to the rational numbers, closed under addition, subtraction, multiplication, and division by a nonzero rational expression; add, subtract, multiply, and divide rational expressions.', 'Algebra', 'Common Core State Standards', true, true, '2010'),

-- Creating Equations (A-CED)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.CED.A.1', 'Create equations and inequalities in one variable and use them to solve problems. Include equations arising from linear and quadratic functions, and simple rational and exponential functions.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.CED.A.2', 'Create equations in two or more variables to represent relationships between quantities; graph equations on coordinate axes with labels and scales.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.CED.A.3', 'Represent constraints by equations or inequalities, and by systems of equations and/or inequalities, and interpret solutions as viable or nonviable options in a modeling context.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.CED.A.4', 'Rearrange formulas to highlight a quantity of interest, using the same reasoning as in solving equations.', 'Algebra', 'Common Core State Standards', true, true, '2010'),

-- Reasoning with Equations & Inequalities (A-REI)
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.A.1', 'Explain each step in solving a simple equation as following from the equality of numbers asserted at the previous step, starting from the assumption that the original equation has a solution. Construct a viable argument to justify a solution method.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.A.2', 'Solve simple rational and radical equations in one variable, and give examples showing how extraneous solutions may arise.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.B.3', 'Solve linear equations and inequalities in one variable, including equations with coefficients represented by letters.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.B.4', 'Solve quadratic equations in one variable.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.B.4a', 'Use the method of completing the square to transform any quadratic equation in x into an equation of the form (x – p)² = q that has the same solutions. Derive the quadratic formula from this form.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.B.4b', 'Solve quadratic equations by inspection (e.g., for x² = 49), taking square roots, completing the square, the quadratic formula and factoring, as appropriate to the initial form of the equation. Recognize when the quadratic formula gives complex solutions and write them as a ± bi for real numbers a and b.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.C.5', 'Prove that, given a system of two equations in two variables, replacing one equation by the sum of that equation and a multiple of the other produces a system with the same solutions.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.C.6', 'Solve systems of linear equations exactly and approximately (e.g., with graphs), focusing on pairs of linear equations in two variables.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.C.7', 'Solve a simple system consisting of a linear equation and a quadratic equation in two variables algebraically and graphically.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.C.8', 'Represent a system of linear equations as a single matrix equation in a vector variable.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.C.9', 'Find the inverse of a matrix if it exists and use it to solve systems of linear equations (using technology for matrices of dimension 3 × 3 or greater).', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.D.10', 'Understand that the graph of an equation in two variables is the set of all its solutions plotted in the coordinate plane, often forming a curve (which could be a line).', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.D.11', 'Explain why the x-coordinates of the points where the graphs of the equations y = f(x) and y = g(x) intersect are the solutions of the equation f(x) = g(x); find the solutions approximately, e.g., using technology to graph the functions, make tables of values, or find successive approximations.', 'Algebra', 'Common Core State Standards', true, true, '2010'),
(gen_random_uuid(), 'CCSS', 'HS', 'Mathematics', 'HSA.REI.D.12', 'Graph the solutions to a linear inequality in two variables as a half-plane (excluding the boundary in the case of a strict inequality), and graph the solution set to a system of linear inequalities in two variables as the intersection of the corresponding half-planes.', 'Algebra', 'Common Core State Standards', true, true, '2010'),

-- ============================================================
-- MATHEMATICS: HIGH SCHOOL — Functions
